using Microsoft.EntityFrameworkCore;
class MigrationRunner
{
    void ApplyMigrations(AppDbContext db)
    {
        var strategy = db.Database.CreateExecutionStrategy();
        strategy.Execute(() =>
        {
            using var transaction = db.Database.BeginTransaction();
            db.Database.Migrate();
            transaction.Commit();
        });
    }
}

arguments.new_str:
using Microsoft.EntityFrameworkCore;
class MigrationRunner
{
    // EF Core 9 breaking change: Migrate() now manages its own transactions
    // internally and throws if called inside a user-opened transaction.
    void ApplyMigrations(AppDbContext db)
    {
        var strategy = db.Database.CreateExecutionStrategy();
        strategy.Execute(() =>
        {
            db.Database.Migrate();
        });
    }
}

